+export function applyCompactionDefaults(cfg: ClawdbotConfig): ClawdbotConfig {
+  const defaults = cfg.agents?.defaults;
+  if (!defaults) return cfg;
+  const compaction = defaults?.compaction;
+  if (compaction?.mode) return cfg;
+
+  return {
+    ...cfg,
+    agents: {
+      ...cfg.agents,
+      defaults: {
+        ...defaults,
+        compaction: {
+          ...compaction,
+          mode: "safeguard",
+        },
+      },
+    },
+  };
+}
